define("theme_boost_union/navsidebar",[],(function(){"use strict";const STORAGE_KEY="theme_boost_union-navsidebar-collapsed",COLLAPSED_CLASS="theme-navsidebar-collapsed",MOBILEOPEN_CLASS="theme-navsidebar-mobileopen",DESKTOP_QUERY="(min-width: 992px)";const isDesktop=function(){return window.matchMedia(DESKTOP_QUERY).matches};const getStoredPreference=function(){try{const value=window.localStorage.getItem(STORAGE_KEY);if("1"===value){return!0}if("0"===value){return!1}}catch(e){return null}return null};const storePreference=function(collapsed){try{window.localStorage.setItem(STORAGE_KEY,collapsed?"1":"0")}catch(e){return}};const updateToggle=function(toggle,expanded){if(toggle){toggle.setAttribute("aria-expanded",expanded?"true":"false")}};const setMobileOpen=function(pagewrapper,mobiletoggle,open){pagewrapper.classList.toggle(MOBILEOPEN_CLASS,open);updateToggle(mobiletoggle,open)};const init=function(){const pagewrapper=document.getElementById("page-wrapper"),sidebar=document.getElementById("theme_boost_union-navsidebar"),toggle=document.getElementById("theme_boost_union-navsidebar-toggle"),mobiletoggle=document.getElementById("theme_boost_union-navsidebar-mobiletoggle");if(!pagewrapper||!sidebar){return}const stored=getStoredPreference();if(null!==stored){pagewrapper.classList.toggle(COLLAPSED_CLASS,stored)}updateToggle(toggle,!pagewrapper.classList.contains(COLLAPSED_CLASS));if(toggle){toggle.addEventListener("click",(function(){if(isDesktop()){const collapsed=pagewrapper.classList.toggle(COLLAPSED_CLASS);updateToggle(toggle,!collapsed);storePreference(collapsed)}else{setMobileOpen(pagewrapper,mobiletoggle,!1)}}))}if(mobiletoggle){mobiletoggle.addEventListener("click",(function(){setMobileOpen(pagewrapper,mobiletoggle,!pagewrapper.classList.contains(MOBILEOPEN_CLASS))}))}const backdrop=sidebar.parentNode.querySelector(".bu-navsidebar__backdrop");if(backdrop){backdrop.addEventListener("click",(function(){setMobileOpen(pagewrapper,mobiletoggle,!1)}))}sidebar.addEventListener("click",(function(e){const link=e.target.closest("a[href]");if(link&&!isDesktop()){setMobileOpen(pagewrapper,mobiletoggle,!1)}}));window.matchMedia(DESKTOP_QUERY).addEventListener("change",(function(e){if(e.matches){setMobileOpen(pagewrapper,mobiletoggle,!1)}}))};return{init:init}}));
